import tiktoken
from functools import lru_cache

@lru_cache(maxsize=8)
def get_encoder(model: str):
    """
    Cache encoder objects at module level.
    Constructing a tiktoken encoder takes ~40ms (disk I/O + BPE data load);
    caching avoids this on every call.
    """
    try:
        return tiktoken.encoding_for_model(model)
    except KeyError:
        # Unknown OpenAI-compatible model: fall back to cl100k_base
        return tiktoken.get_encoding("cl100k_base")


def count_tokens(text: str, model: str = "gpt-4o") -> int:
    """Count tokens in a plain string using the specified model's tokenizer."""
    return len(get_encoder(model).encode(text, disallowed_special=()))


def count_chat_tokens(messages: list[dict], model: str = "gpt-4o") -> int:
    """
    Estimate total tokens for a chat messages array, including
    per-message framing overhead (3 tokens for role + delimiters).
    Based on OpenAI's published counting method.
    """
    enc = get_encoder(model)
    total = 3  # every reply is primed with <|start|>assistant<|message|>
    for msg in messages:
        total += 3  # role framing
        for value in msg.values():
            if isinstance(value, str):
                total += len(enc.encode(value, disallowed_special=()))
    return total


def truncate_to_tokens(text: str, max_tokens: int, model: str = "gpt-4o") -> str:
    """
    Return the longest prefix of text that fits within max_tokens.
    Decodes cleanly — no partial UTF-8 sequences.
    """
    enc = get_encoder(model)
    ids = enc.encode(text, disallowed_special=())
    if len(ids) <= max_tokens:
        return text
    return enc.decode(ids[:max_tokens])


# --- Example usage ---
system = "You are a data analyst agent. Use the query_database tool to answer questions."
user   = "What were the top 10 products by revenue last quarter?"

messages = [
    {"role": "system", "content": system},
    {"role": "user",   "content": user},
]

print(f"System prompt : {count_tokens(system)} tokens")
print(f"User message  : {count_tokens(user)} tokens")
print(f"Full request  : {count_chat_tokens(messages)} tokens (with framing)")
